## Phase 1: Shared Types (`src/shared/types.ts` + `src/shared/parse.ts`)

### `src/shared/types.ts`

Adopt the types from the handoff doc with these adjustments:

1. **Export everything** — both agents import from here
2. **Add `id` field to PresenceChange and TaskUpdate** — every event needs a unique ID for the client's key prop and journal dedup
3. **Add a `JournalEntry` type** wrapping `ChatEvent` with sequence number for replay ordering
4. **Use string literal unions instead of bare strings** for discriminated union correctness
5. **Add `RawInboxMessage` type** for the raw JSON from inbox files (before processing)
6. **Add `RawTaskData` type** for the raw JSON from task files
7. **Add `TeamConfig` type** for config.json structure

Full type list:
```typescript
// Raw filesystem types (input)
export interface RawInboxMessage {
  from: string;
  text: string;
  summary?: string;
  timestamp: string;
  color: string;
  read: boolean;
}

export interface RawTaskData {
  id: string;
  subject: string;
  description: string | null;
  status: 'pending' | 'in_progress' | 'completed' | 'failed';
  owner: string | null;
  blockedBy: string[] | null;
  activeForm: string | null;
  created: string;
  updated: string;
}

export interface AgentInfo {
  name: string;
  agentId: string;
  agentType: string;
  color: string;
}

export interface TeamConfig {
  members: AgentInfo[];
}

export interface TeamState {
  name: string;
  members: AgentInfo[];
}

// Task info (processed)
export interface TaskInfo {
  id: string;
  subject: string;
  description: string | null;
  status: 'pending' | 'in_progress' | 'completed' | 'failed';
  owner: string | null;
  blockedBy: string[] | null;
  activeForm: string | null;
  created: string;
  updated: string;
}

// ChatEvent discriminated union (server -> client via WebSocket)
export type ChatEvent =
  | ContentMessage
  | SystemEvent
  | ReactionEvent
  | ThreadMarker
  | PresenceChange
  | TaskUpdate;

export interface ContentMessage {
  type: 'message';
  id: string;
  from: string;
  fromColor: string;
  text: string;
  summary: string | null;
  timestamp: string;
  isBroadcast: boolean;
  isDM: boolean;
  dmParticipants: string[] | null;
  isLead: boolean;
  replyToId: string | null;
}

export interface SystemEvent {
  type: 'system';
  id: string;
  subtype:
    | 'member-joined'
    | 'member-left'
    | 'task-created'
    | 'task-claimed'
    | 'task-completed'
    | 'task-failed'
    | 'task-unblocked'
    | 'all-tasks-completed'
    | 'shutdown-requested'
    | 'shutdown-approved'
    | 'shutdown-rejected'
    | 'team-created'
    | 'team-deleted'
    | 'idle-surfaced';
  text: string;
  timestamp: string;
  agentName: string | null;
  agentColor: string | null;
  taskId: string | null;
  taskSubject: string | null;
}

export interface ReactionEvent {
  type: 'reaction';
  id: string;
  targetMessageId: string;
  emoji: string;
  fromAgent: string;
  fromColor: string;
  timestamp: string;
  tooltip: string | null;
}

export interface ThreadMarker {
  type: 'thread-marker';
  id: string;
  subtype: 'thread-start' | 'thread-end';
  participants: string[];
  timestamp: string;
}

export interface PresenceChange {
  type: 'presence';
  id: string;
  agentName: string;
  status: 'working' | 'idle' | 'offline';
  timestamp: string;
}

export interface TaskUpdate {
  type: 'task-update';
  id: string;
  task: TaskInfo;
  timestamp: string;
}

// Initial state for REST hydration
export interface SessionState {
  team: TeamState;
  events: ChatEvent[];
  tasks: TaskInfo[];
  presence: Record<string, 'working' | 'idle' | 'offline'>;
  sessionStart: string;
}

// Plan/Permission card data (embedded in ContentMessage text or as structured data)
export interface PlanApprovalCard {
  type: 'plan-approval';
  requestId: string;
  from: string;
  planContent: string;
  status: 'pending' | 'approved' | 'rejected';
