}

export interface PermissionRequestCard {
  type: 'permission-request';
  requestId: string;
  agentName: string;
  toolName: string;
  command: string;
  status: 'pending' | 'approved' | 'denied';
}

// Journal entry wrapper
export interface JournalEntry {
  seq: number;
  event: ChatEvent;
}

// System event type strings parsed from inbox message text field
export type SystemEventType =
  | 'idle_notification'
  | 'shutdown_request'
  | 'shutdown_approved'
  | 'shutdown_rejected'
  | 'task_completed'
  | 'plan_approval_request'
  | 'plan_approval_response'
  | 'join_request'
  | 'permission_request'
  | 'task_assignment';

